### **4. `js/database/FirestoreService.js`**

Dịch vụ này sẽ xử lý tất cả các tương tác với Firestore (thêm, lấy, cập nhật, xóa Todo).

```javascript
// js/database/FirestoreService.js
import { db } from './firebase.js';
import { collection, addDoc, getDocs, updateDoc, deleteDoc, doc, query, orderBy } from "https://www.gstatic.com/firebasejs/9.6.1/firebase-firestore.js";

const TODO_COLLECTION = "todos";

class FirestoreService {
    constructor() {
        this.todosCollection = collection(db, TODO_COLLECTION);
    }

    async addTodo(taskText) {
        try {
            const docRef = await addDoc(this.todosCollection, {
                text: taskText,
                completed: false,
                createdAt: new Date()
            });
            return { id: docRef.id, text: taskText, completed: false, createdAt: new Date() };
        } catch (e) {
            console.error("Lỗi khi thêm tài liệu: ", e);
            throw e;
        }
    }

    async getTodos() {
        try {
            const q = query(this.todosCollection, orderBy("createdAt", "desc"));
            const querySnapshot = await getDocs(q);
            const todos = [];
            querySnapshot.forEach((doc) => {
                todos.push({ id: doc.id, ...doc.data() });
            });
            return todos;
        } catch (e) {
            console.error("Lỗi khi lấy tài liệu: ", e);
            throw e;
        }
    }

    async updateTodoStatus(id, completed) {
        try {
            const todoRef = doc(db, TODO_COLLECTION, id);
            await updateDoc(todoRef, {
                completed: completed
            });
            return true;
        } catch (e) {
            console.error("Lỗi khi cập nhật trạng thái: ", e);
            throw e;
        }
    }

    async deleteTodo(id) {
        try {
            const todoRef = doc(db, TODO_COLLECTION, id);
            await deleteDoc(todoRef);
            return true;
        } catch (e) {
            console.error("Lỗi khi xóa tài liệu: ", e);
            throw e;
        }
    }
}

export const firestoreService = new FirestoreService();
```

