### **5. `js/services/GeminiProvider.js`**

Class này sẽ là cầu nối để tương tác với Gemini API. Để đơn giản hóa, tôi sẽ sử dụng một placeholder cho đến khi bạn cấu hình API Key thực sự.

**Để sử dụng Gemini API thực sự:**
1.  Truy cập Google AI Studio để lấy API Key của Gemini.
2.  Bạn sẽ cần một thư viện như `@google/generative-ai` hoặc gọi API trực tiếp. Với cấu trúc module hiện tại, việc sử dụng thư viện trực tiếp có thể phức tạp một chút do hạn chế CORS nếu không có proxy backend.
3.  Để demo ngay trên frontend, tôi sẽ sử dụng một phản hồi mock. Nếu bạn muốn tích hợp thực tế, bạn *nên* sử dụng một backend server (ví dụ: Node.js với Express) để gọi Gemini API, tránh lộ API Key.

```javascript
// js/services/GeminiProvider.js

// LƯU Ý QUAN TRỌNG:
// Trong một ứng dụng thực tế, bạn KHÔNG NÊN nhúng API Key trực tiếp vào mã frontend
// vì điều này sẽ làm lộ khóa của bạn. Thay vào đó, bạn nên có một backend server
// (ví dụ: Node.js, Python, Go, etc.) đóng vai trò proxy để gọi Gemini API.
// Frontend sẽ gọi backend của bạn, và backend sẽ gọi Gemini API.

const GEMINI_API_KEY = "YOUR_GEMINI_API_KEY"; // Thay thế bằng API Key Gemini của bạn

class GeminiProvider {
    constructor() {
        if (!GEMINI_API_KEY || GEMINI_API_KEY === "YOUR_GEMINI_API_KEY") {
            console.warn("Gemini API Key chưa được cấu hình. Tính năng AI sẽ sử dụng dữ liệu giả.");
            this.isMock = true;
        } else {
            this.isMock = false;
            // Khởi tạo Gemini client nếu dùng thư viện @google/generative-ai
            // import { GoogleGenerativeAI } from "@google/generative-ai";
            // this.genAI = new GoogleGenerativeAI(GEMINI_API_KEY);
            // this.model = this.genAI.getGenerativeModel({ model: "gemini-pro" });
        }
    }

    async generateContent(prompt) {
        if (this.isMock) {
            console.log("Mocking Gemini response for prompt:", prompt);
            // Phản hồi giả lập cho mục đích demo
            return new Promise(resolve => {
                setTimeout(() => {
                    if (prompt.includes("đi chợ")) {
                        resolve("Mua rau, thịt, cá, trái cây.");
                    } else if (prompt.includes("học bài")) {
                        resolve("Ôn tập kiến thức, làm bài tập, đọc sách tham khảo.");
                    } else {
                        resolve("Một công việc đã được gợi ý bởi AI.");
                    }
                }, 1500); // Giả lập độ trễ API
            });
        }

        try {
            // Đây là cách bạn có thể gọi Gemini API nếu bạn có một backend proxy
            // hoặc nếu bạn sử dụng thư viện trong môi trường Node.js.
            // Để gọi trực tiếp từ frontend, cần xử lý CORS và tránh lộ API Key.
            // Ví dụ: gọi một endpoint backend của riêng bạn.
            const response = await fetch('YOUR_BACKEND_GEMINI_PROXY_URL', { // Thay thế URL này
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    // 'Authorization': `Bearer ${GEMINI_API_KEY}` // CHỈ DÙNG TRÊN BACKEND!
                },
                body: JSON.stringify({ prompt: prompt })
            });

            if (!response.ok) {
                throw new Error(`HTTP error! status: ${response.status}`);
            }

            const data = await response.json();
            // Tùy thuộc vào định dạng phản hồi từ Gemini API hoặc proxy của bạn
            return data.text || data.generated_content; 

        } catch (error) {
            console.error("Lỗi khi gọi Gemini API:", error);
            // Fallback to mock data if API call fails
            return "Xin lỗi, không thể tạo gợi ý lúc này. Vui lòng thử lại.";
        }
    }
}

export const geminiProvider = new GeminiProvider();
```

