// js/services/AIService.js
import { geminiProvider } from './GeminiProvider.js';
import { promptBuilder } from './PromptBuilder.js';

class AIService {
    async suggestTaskTitle(input) {
        if (!input || input.trim() === '') {
            return "Vui lòng nhập một mô tả để tôi có thể gợi ý.";
        }
        const prompt = promptBuilder.buildTaskSuggestionPrompt(input);
        try {
            const suggestion = await geminiProvider.generateContent(prompt);
            return suggestion.trim();
        } catch (error) {
            console.error("Lỗi khi gợi ý công việc bằng AI:", error);
            return "Có lỗi xảy ra khi tạo gợi ý. Vui lòng thử lại.";
        }
    }

