### **8. `js/core/MemoryService.js`**

Dịch vụ quản lý bộ nhớ trạng thái ứng dụng. Trong bản Todo đơn giản này, nó sẽ chỉ lưu trữ danh sách các Todo hiện tại trong bộ nhớ.

```javascript
// js/core/MemoryService.js

class MemoryService {
    constructor() {
        this.state = {
            todos: []
        };
        this.listeners = []; // Để các component khác có thể đăng ký lắng nghe thay đổi
    }

    getTodos() {
        return [...this.state.todos]; // Trả về bản sao để tránh thay đổi trực tiếp
    }

    setTodos(newTodos) {
        this.state.todos = newTodos;
        this._notifyListeners();
    }

    addTodo(todo) {
        this.state.todos.unshift(todo); // Thêm vào đầu danh sách
        this._notifyListeners();
    }

    updateTodo(id, updatedFields) {
        this.state.todos = this.state.todos.map(todo => 
            todo.id === id ? { ...todo, ...updatedFields } : todo
        );
        this._notifyListeners();
    }

    deleteTodo(id) {
        this.state.todos = this.state.todos.filter(todo => todo.id !== id);
        this._notifyListeners();
    }

    // Phương thức để đăng ký lắng nghe thay đổi trạng thái
    subscribe(callback) {
        this.listeners.push(callback);
        return () => { // Hàm hủy đăng ký
            this.listeners = this.listeners.filter(listener => listener !== callback);
        };
    }

    _notifyListeners() {
        this.listeners.forEach(listener => listener(this.state));
    }
}

export const memoryService = new MemoryService();
```

