### **9. `js/router.js`**

Tệp router trống, sẵn sàng cho việc mở rộng ứng dụng với nhiều trang hoặc chế độ xem khác nhau.

```javascript
// js/router.js
// Đây là một placeholder cho hệ thống định tuyến (routing) nếu ứng dụng cần nhiều trang.
// Đối với ứng dụng Todo List đơn giản này, chúng ta không cần routing.

class Router {
    constructor() {
        this.routes = {};
        window.addEventListener('popstate', this.handleRouting.bind(this));
        document.addEventListener('DOMContentLoaded', this.handleRouting.bind(this));
    }

    addRoute(path, callback) {
        this.routes[path] = callback;
    }

    navigate(path) {
        window.history.pushState(null, null, path);
        this.handleRouting();
    }

    handleRouting() {
        const currentPath = window.location.pathname;
        const handler = this.routes[currentPath];
        if (handler) {
            handler();
        } else {
            console.warn(`No route found for path: ${currentPath}`);
            // Xử lý trang 404 hoặc chuyển hướng đến trang chủ
        }
    }
}

export const router = new Router();
