```javascript
// js/core/orchestrator/steps/StepManager.js
// Quản lý các bước (steps) riêng lẻ trong một pipeline AI.
// Mỗi bước có thể là một hàm xử lý dữ liệu, gọi API, v.v.
// Đối với ứng dụng Todo List đơn giản, chúng ta chưa cần đến nó.

class StepManager {
    constructor() {
        this.steps = new Map();
    }

    registerStep(name, handler) {
        if (this.steps.has(name)) {
            console.warn(`Step "${name}" already registered. Overwriting.`);
        }
        this.steps.set(name, handler);
    }

    getStep(name) {
        const step = this.steps.get(name);
        if (!step) {
            console.error(`Step "${name}" not found.`);
        }
        return step;
    }

    async executeStep(name, input, context) {
        const stepHandler = this.getStep(name);
        if (stepHandler) {
            console.log(`Executing step: ${name}`);
            return await stepHandler(input, context);
        }
        return null;
    }
}

export const stepManager = new StepManager();
