### **13. `js/app.js`**

Đây là tệp chứa logic chính của ứng dụng Todo List, liên kết các dịch vụ lại với nhau và xử lý tương tác người dùng.

```javascript
// js/app.js
import { firestoreService } from './database/FirestoreService.js';
import { memoryService } from './core/MemoryService.js';
import { aiService } from './services/AIService.js';

const todoInput = document.getElementById('todoInput');
const addTodoBtn = document.getElementById('addTodoBtn');
const todoList = document.getElementById('todoList');
const loadingIndicator = document.getElementById('loadingIndicator');
const aiSuggestInput = document.getElementById('aiSuggestInput');
const aiSuggestBtn = document.getElementById('aiSuggestBtn');
const aiSuggestionOutput = document.getElementById('aiSuggestionOutput');

// Hiển thị/ẩn trạng thái tải
function toggleLoading(show) {
    if (show) {
        loadingIndicator.classList.add('active');
    } else {
        loadingIndicator.classList.remove('active');
    }
}

// Render danh sách công việc
function renderTodos() {
    todoList.innerHTML = ''; // Xóa danh sách cũ
    const todos = memoryService.getTodos();

    if (todos.length === 0) {
        todoList.innerHTML = '<li class="empty-list">Chưa có công việc nào. Thêm công việc mới!</li>';
        return;
    }

    todos.forEach(todo => {
        const li = document.createElement('li');
        li.dataset.id = todo.id;
        if (todo.completed) {
            li.classList.add('completed');
        }

        const taskTextSpan = document.createElement('span');
        taskTextSpan.classList.add('task-text');
        taskTextSpan.textContent = todo.text;
        li.appendChild(taskTextSpan);

        const actionsDiv = document.createElement('div');
        actionsDiv.classList.add('task-actions');

        const completeBtn = document.createElement('button');
        completeBtn.classList.add('complete-btn');
        completeBtn.textContent = todo.completed ? 'Hoàn tác' : 'Hoàn thành';
        completeBtn.addEventListener('click', () => toggleTodoStatus(todo.id, !todo.completed));
        actionsDiv.appendChild(completeBtn);

        const deleteBtn = document.createElement('button');
        deleteBtn.classList.add('delete-btn');
        deleteBtn.textContent = 'Xóa';
        deleteBtn.addEventListener('click', () => deleteTodo(todo.id));
        actionsDiv.appendChild(deleteBtn);

        li.appendChild(actionsDiv);
        todoList.appendChild(li);
    });
}

// Tải công việc từ Firestore khi khởi động
async function loadTodos() {
    toggleLoading(true);
    try {
        const todos = await firestoreService.getTodos();
        memoryService.setTodos(todos); // Cập nhật trạng thái trong MemoryService
    } catch (error) {
        console.error("Lỗi khi tải công việc:", error);
        alert("Không thể tải công việc. Vui lòng kiểm tra kết nối mạng hoặc cấu hình Firebase.");
    } finally {
        toggleLoading(false);
    }
}

// Thêm công việc mới
async function addTodo() {
    const taskText = todoInput.value.trim();
    if (taskText === '') {
        alert('Vui lòng nhập tên công việc!');
        return;
    }

    toggleLoading(true);
    try {
        const newTodo = await firestoreService.addTodo(taskText);
        memoryService.addTodo(newTodo); // Thêm vào MemoryService
        todoInput.value = '';
    } catch (error) {
        console.error("Lỗi khi thêm công việc:", error);
        alert("Không thể thêm công việc. Vui lòng thử lại.");
    } finally {
        toggleLoading(false);
    }
}

// Chuyển đổi trạng thái công việc (hoàn thành/chưa hoàn thành)
async function toggleTodoStatus(id, completed) {
    toggleLoading(true);
    try {
        await firestoreService.updateTodoStatus(id, completed);
        memoryService.updateTodo(id, { completed }); // Cập nhật trong MemoryService
    } catch (error) {
        console.error("Lỗi khi cập nhật trạng thái công việc:", error);
        alert("Không thể cập nhật trạng thái. Vui lòng thử lại.");
    } finally {
        toggleLoading(false);
    }
}

// Xóa công việc
async function deleteTodo(id) {
    if (!confirm('Bạn có chắc chắn muốn xóa công việc này?')) {
        return;
    }

    toggleLoading(true);
    try {
        await firestoreService.deleteTodo(id);
        memoryService.deleteTodo(id); // Xóa khỏi MemoryService
    } catch (error) {
        console.error("Lỗi khi xóa công việc:", error);
        alert("Không thể xóa công việc. Vui lòng thử lại.");
    } finally {
        toggleLoading(false);
    }
}

// Sử dụng AI để gợi ý tiêu đề công việc
async function suggestTask() {
    const input = aiSuggestInput.value.trim();
    if (!input) {
        aiSuggestionOutput.textContent = "Vui lòng nhập mô tả để AI gợi ý.";
        return;
    }

    aiSuggestBtn.disabled = true;
    aiSuggestBtn.textContent = 'Đang gợi ý...';
    aiSuggestionOutput.textContent = 'Đang tạo gợi ý từ AI...';

    try {
        const suggestion = await aiService.suggestTaskTitle(input);
        aiSuggestionOutput.textContent = `Gợi ý của AI: "${suggestion}"`;
        // Có thể tự động điền vào todoInput nếu muốn
        // todoInput.value = suggestion; 
    } catch (error) {
        console.error("Lỗi khi gợi ý bằng AI:", error);
        aiSuggestionOutput.textContent = "Không thể tạo gợi ý lúc này. Vui lòng thử lại.";
    } finally {
        aiSuggestBtn.disabled = false;
        aiSuggestBtn.textContent = 'Gợi ý AI';
    }
}

// Thêm Event Listeners
addTodoBtn.addEventListener('click', addTodo);
todoInput.addEventListener('keypress', (e) => {
    if (e.key === 'Enter') {
        addTodo();
    }
});
aiSuggestBtn.addEventListener('click', suggestTask);
aiSuggestInput.addEventListener('keypress', (e) => {
    if (e.key === 'Enter') {
        suggestTask();
    }
});

// Đăng ký lắng nghe thay đổi trạng thái từ MemoryService
memoryService.subscribe(state => {
    renderTodos();
});

// Khởi tạo ứng dụng
document.addEventListener('DOMContentLoaded', loadTodos);
```

